import{c as s,Q as e,j as i,m as l}from"./chunks/framework.Bhbi9jCp.js";const u=JSON.parse('{"title":"带宽、CDN、存储与成本","description":"","frontmatter":{},"headers":[],"relativePath":"mediaTechLearning/29-带宽-CDN-存储与成本.md","filePath":"mediaTechLearning/29-带宽-CDN-存储与成本.md","lastUpdated":1780887690000}'),t={name:"mediaTechLearning/29-带宽-CDN-存储与成本.md"};function n(p,a,o,r,c,d){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="带宽、cdn、存储与成本" tabindex="-1">带宽、CDN、存储与成本 <a class="header-anchor" href="#带宽、cdn、存储与成本" aria-label="Permalink to &quot;带宽、CDN、存储与成本&quot;">​</a></h1><p>音视频系统最贵的通常不是机器,是带宽、CDN、存储和转码。</p><blockquote><p>一句话先记住:<strong>音视频成本 = 流量成本 + 存储成本 + 转码成本 + 实时中继成本</strong>。清晰度和延迟都是钱。</p></blockquote><hr><h2 id="一、带宽账" tabindex="-1">一、带宽账 <a class="header-anchor" href="#一、带宽账" aria-label="Permalink to &quot;一、带宽账&quot;">​</a></h2><p>1000 个用户看 3Mbps 直播:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3 Mbps x 1000 = 3000 Mbps = 3 Gbps</span></span></code></pre></div><p>看一小时流量:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>3 Mbps / 8 x 3600 x 1000</span></span>
<span class="line"><span>≈ 1.35 TB</span></span></code></pre></div><p>这就是为什么直播一定要算账。</p><hr><h2 id="二、点播存储账" tabindex="-1">二、点播存储账 <a class="header-anchor" href="#二、点播存储账" aria-label="Permalink to &quot;二、点播存储账&quot;">​</a></h2><p>一个 1GB 原片,转 3 档:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>原片 1GB</span></span>
<span class="line"><span>1080p 800MB</span></span>
<span class="line"><span>720p  400MB</span></span>
<span class="line"><span>480p  200MB</span></span>
<span class="line"><span>HLS 分片和索引</span></span></code></pre></div><p>总存储可能超过 2GB。再加封面、预览、字幕、备份,会继续涨。</p><hr><h2 id="三、转码成本" tabindex="-1">三、转码成本 <a class="header-anchor" href="#三、转码成本" aria-label="Permalink to &quot;三、转码成本&quot;">​</a></h2><p>转码吃 CPU / GPU。影响因素:</p><ul><li>分辨率</li><li>编码格式</li><li>preset</li><li>是否多档</li><li>是否水印 / 滤镜</li><li>是否硬件编码</li></ul><p>AV1 高质量编码可能非常慢。不要只看输出文件大小,还要看转码时长和机器成本。</p><hr><h2 id="四、cdn-策略" tabindex="-1">四、CDN 策略 <a class="header-anchor" href="#四、cdn-策略" aria-label="Permalink to &quot;四、CDN 策略&quot;">​</a></h2><p>点播:</p><ul><li>热内容长缓存</li><li>冷内容转低频存储</li><li>多清晰度按需生成</li></ul><p>直播:</p><ul><li>热房间边缘分发</li><li>清单短缓存</li><li>分片适度缓存</li><li>断流后清理</li></ul><hr><h2 id="五、turn-sfu-成本" tabindex="-1">五、TURN / SFU 成本 <a class="header-anchor" href="#五、turn-sfu-成本" aria-label="Permalink to &quot;五、TURN / SFU 成本&quot;">​</a></h2><p>WebRTC 成本模型:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TURN: 中继流量 = 双向媒体流量</span></span>
<span class="line"><span>SFU: 上行少,服务端下行多</span></span></code></pre></div><p>多人会议 10 人,每人发 1Mbps,每人收 9Mbps。SFU 总出口大致:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10 x 9 Mbps = 90 Mbps</span></span></code></pre></div><p>这还不算 simulcast 多层和录制。</p><hr><h2 id="六、降本手段" tabindex="-1">六、降本手段 <a class="header-anchor" href="#六、降本手段" aria-label="Permalink to &quot;六、降本手段&quot;">​</a></h2><ul><li>多码率,弱网用户不强推高清</li><li>冷门视频按需转码</li><li>旧视频转冷存储</li><li>限制直播最高码率</li><li>房间无人时停止转发和录制</li><li>屏幕共享降帧率</li><li>音频优先,视频降级</li></ul><hr><h2 id="七、踩坑提醒" tabindex="-1">七、踩坑提醒 <a class="header-anchor" href="#七、踩坑提醒" aria-label="Permalink to &quot;七、踩坑提醒&quot;">​</a></h2><ol><li><strong>用峰值直播规模算晚了</strong>——活动当天才知道会很贵。</li><li><strong>所有视频全量转多档</strong>——长尾内容浪费。</li><li><strong>TURN 不限速不限额</strong>——账单风险大。</li><li><strong>录制默认永久保存</strong>——存储会持续涨。</li><li><strong>低延迟默认全开</strong>——成本远高于普通 CDN。</li></ol><p>下一篇:<code>30-音视频工程的未来.md</code>。</p>`,40)])])}const b=s(t,[["render",n]]);export{u as __pageData,b as default};
